import{_ as e,o as r,c as t,f as s}from"./app-55c326ac.js";const c={},o=s('<h1 id="_10-修改docker的启动项" tabindex="-1"><a class="header-anchor" href="#_10-修改docker的启动项" aria-hidden="true">#</a> 10. 修改docker的启动项</h1><p>一般主要修改的就是 存储路径 安全信任 国内源</p><p>版本docker-ce 配置文件位置：/lib/systemd/system/docker.service 在ExecStart一句后面加上：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>    -insecure-registry ``IP或者域名`` -g ${YOUR_PATH}  \n    -registry-mirror=https://IP或者域名  \n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>-g：后面是存储路径</strong><br><strong>-insecure-registry：是将网址加入到信任</strong><br><strong>-registry-mirror:是加入镜像源</strong></p><p>之后重新启动docker</p>',6),n=[o];function i(d,a){return r(),t("div",null,n)}const l=e(c,[["render",i],["__file","Docker系列学习-10.修改docker启动项.html.vue"]]);export{l as default};
